import React, { Component } from 'react';
import {
  View,
  Text,
  FlatList,
  TouchableOpacity,
  ActivityIndicator,
  Alert,
  StyleSheet,
} from 'react-native';
import Header from '../components/Header';
import { getUserName, getChannelDisplayName } from '../utils/format';

export default class ChannelInfoScreen extends Component {
  constructor(props) {
    super(props);
    this.state = {
      members: [],
      loading: true,
      pins: [],
      pinsLoading: true,
      showPins: false,
    };
  }

  componentDidMount() {
    this.loadMembers();
    this.loadPins();
  }

  async loadMembers() {
    var { slack, channel } = this.props;
    try {
      var res = await slack.conversationsMembers(channel.id);
      this.setState({ members: res.members || [], loading: false });
    } catch (err) {
      this.setState({ loading: false });
    }
  }

  async loadPins() {
    var { slack, channel } = this.props;
    try {
      var res = await slack.pinsList(channel.id);
      this.setState({ pins: res.items || [], pinsLoading: false });
    } catch (err) {
      this.setState({ pinsLoading: false });
    }
  }

  renderMember(userId) {
    var { usersMap, onProfile } = this.props;
    var name = getUserName(userId, usersMap);

    return (
      <TouchableOpacity
        style={styles.memberItem}
        onPress={function () { onProfile && onProfile(userId); }}
      >
        <Text style={styles.memberName}>{name}</Text>
        <Text style={styles.memberArrow}>{'>'}</Text>
      </TouchableOpacity>
    );
  }

  renderPin(item) {
    var { usersMap } = this.props;
    var msg = item.message;
    if (!msg) return null;
    var userName = getUserName(msg.user, usersMap);

    return (
      <View style={styles.pinItem}>
        <Text style={styles.pinUser}>{userName}</Text>
        <Text style={styles.pinText} numberOfLines={3}>{msg.text}</Text>
      </View>
    );
  }

  render() {
    var { channel, usersMap, currentUserId, onBack, onProfile } = this.props;
    var { members, loading, pins, pinsLoading, showPins } = this.state;
    var self = this;
    var channelName = getChannelDisplayName(channel, usersMap, currentUserId);

    return (
      <View style={styles.container}>
        <Header title="Info" onBack={onBack} />

        <View style={styles.infoSection}>
          <Text style={styles.channelName}>
            {!channel.is_im ? '# ' : ''}{channelName}
          </Text>
          {channel.purpose && channel.purpose.value ? (
            <Text style={styles.purpose}>{channel.purpose.value}</Text>
          ) : null}
          {channel.topic && channel.topic.value ? (
            <Text style={styles.topic}>Topic: {channel.topic.value}</Text>
          ) : null}
          <Text style={styles.memberCount}>{members.length} members</Text>
        </View>

        <View style={styles.tabRow}>
          <TouchableOpacity
            style={[styles.tabBtn, !showPins && styles.tabBtnActive]}
            onPress={function () { self.setState({ showPins: false }); }}
          >
            <Text style={[styles.tabBtnText, !showPins && styles.tabBtnTextActive]}>Members</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.tabBtn, showPins && styles.tabBtnActive]}
            onPress={function () { self.setState({ showPins: true }); }}
          >
            <Text style={[styles.tabBtnText, showPins && styles.tabBtnTextActive]}>
              Pins ({pins.length})
            </Text>
          </TouchableOpacity>
        </View>

        {!showPins ? (
          loading ? (
            <View style={styles.center}>
              <ActivityIndicator size="large" color="#4A90D9" />
            </View>
          ) : (
            <FlatList
              data={members}
              keyExtractor={function (item) { return item; }}
              renderItem={function (obj) { return self.renderMember(obj.item); }}
            />
          )
        ) : (
          pinsLoading ? (
            <View style={styles.center}>
              <ActivityIndicator size="large" color="#4A90D9" />
            </View>
          ) : (
            <FlatList
              data={pins}
              keyExtractor={function (item, i) { return '' + i; }}
              renderItem={function (obj) { return self.renderPin(obj.item); }}
              ListEmptyComponent={
                <View style={styles.center}>
                  <Text style={styles.emptyText}>No pinned messages</Text>
                </View>
              }
            />
          )
        )}
      </View>
    );
  }
}

var styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#1a1a2e',
  },
  infoSection: {
    padding: 16,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#2a2a4e',
  },
  channelName: {
    color: '#ffffff',
    fontSize: 20,
    fontWeight: 'bold',
    marginBottom: 4,
  },
  purpose: {
    color: '#aaaacc',
    fontSize: 13,
    marginBottom: 4,
  },
  topic: {
    color: '#8888aa',
    fontSize: 12,
    marginBottom: 4,
  },
  memberCount: {
    color: '#666688',
    fontSize: 12,
    marginTop: 4,
  },
  tabRow: {
    flexDirection: 'row',
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#2a2a4e',
  },
  tabBtn: {
    flex: 1,
    paddingVertical: 10,
    alignItems: 'center',
  },
  tabBtnActive: {
    borderBottomWidth: 2,
    borderBottomColor: '#4A90D9',
  },
  tabBtnText: {
    color: '#8888aa',
    fontSize: 14,
  },
  tabBtnTextActive: {
    color: '#4A90D9',
    fontWeight: 'bold',
  },
  center: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: 40,
  },
  emptyText: {
    color: '#666688',
    fontSize: 14,
  },
  memberItem: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 14,
    paddingVertical: 12,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#1a2338',
  },
  memberName: {
    flex: 1,
    color: '#ccccdd',
    fontSize: 14,
  },
  memberArrow: {
    color: '#555577',
    fontSize: 14,
  },
  pinItem: {
    paddingHorizontal: 14,
    paddingVertical: 10,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#1a2338',
  },
  pinUser: {
    color: '#ccccdd',
    fontSize: 13,
    fontWeight: 'bold',
    marginBottom: 2,
  },
  pinText: {
    color: '#aaaacc',
    fontSize: 13,
  },
});
